module top_module(
    input CLK,
    input RST,
    input START,
    input [15:0] DURATION,
    output reg PULSE
);reg [15:0] obf_count;

always @(posedge CLK) begin
    if (RST) begin
        obf_count <= 0;
        PULSE <= 0;
    end
    else if (START) begin
        if (obf_count < DURATION) begin
            obf_count <= obf_count + 1;
            PULSE <= 1;
        end
        else begin
            obf_count <= 0;
            PULSE <= 0;
        end
    end
    else begin
        obf_count <= 0;
        PULSE <= 0;
    end
end

endmodule
